import heapq

class AğırlıklıGrafik:
    def __init__(self):
        self.grafik = {}

    def kenar_ekle(self, düğüm1, düğüm2, ağırlık):
        if düğüm1 not in self.grafik:
            self.grafik[düğüm1] = []
        if düğüm2 not in self.grafik:
            self.grafik[düğüm2] = []

        self.grafik[düğüm1].append((düğüm2, ağırlık))
        self.grafik[düğüm2].append((düğüm1, ağırlık))  # Eğer grafik yönsüz ise

    def dijkstra(self, başlangıç_düğümü):
        mesafeler = {düğüm: float('inf') for düğüm in self.grafik}
        mesafeler[başlangıç_düğümü] = 0
        kuyruk = [(0, başlangıç_düğümü)]  # (mesafe, düğüm)

        while kuyruk:
            mevcut_mesafe, mevcut_düğüm = heapq.heappop(kuyruk)

            if mevcut_mesafe > mesafeler[mevcut_düğüm]:
                continue

            for komşu, ağırlık in self.grafik[mevcut_düğüm]:
                mesafe = mevcut_mesafe + ağırlık
                if mesafe < mesafeler[komşu]:
                    mesafeler[komşu] = mesafe
                    heapq.heappush(kuyruk, (mesafe, komşu))

        return mesafeler

if __name__ == '__main__':
    # Örnek kullanım
    grafik = AğırlıklıGrafik()
    grafik.kenar_ekle('A', 'B', 4)
    grafik.kenar_ekle('A', 'C', 2)
    grafik.kenar_ekle('B', 'C', 5)
    grafik.kenar_ekle('B', 'D', 10)
    grafik.kenar_ekle('C', 'E', 3)
    grafik.kenar_ekle('D', 'F', 11)
    grafik.kenar_ekle('E', 'D', 4)

    başlangıç_düğümü = 'A'
    mesafeler = grafik.dijkstra(başlangıç_düğümü)

    print(f"Başlangıç Düğümü: {başlangıç_düğümü}")
    for düğüm, mesafe in mesafeler.items():
        print(f"Düğüm {düğüm}: Mesafe = {mesafe}")
